export class Vector2 {
    x: number;
    y: number;

    constructor() {
        this.x = 0;
        this.y = 0;
    }

    static create(x: number, y: number): Vector2 {
        var vec = new Vector2();
        vec.x = x;
        vec.y = y;
        return vec;
    }

    add(v: Vector2) {
        this.x += v.x;
        this.y += v.y;
    }

    sub(v: Vector2) {
        this.x += v.x;
        this.y += v.y;
    }

    mul(v: Vector2) {
        this.x *= v.x;
        this.y *= v.y;
    }

    div(v: Vector2) {
        this.x /= v.x;
        this.y /= v.y;
    }
}

export class Rect {    
    topLeft: Vector2;
    btmRight: Vector2;

    constructor() {
        this.topLeft = new Vector2();
        this.btmRight = new Vector2();
    }

    static create(topLeft: Vector2, btmRight: Vector2): Rect {
        var rect = new Rect();

        rect.topLeft = topLeft;
        rect.btmRight = btmRight;

        return rect;
    }
}