export enum PaletteIndex {
    PALETTE_0 = 0x0,
    PALETTE_BACKGROUND = PALETTE_0, // define background layer
    PALETTE_1 = 0x1,
    PALETTE_2 = 0x2,
    PALETTE_3 = 0x3,
    PALETTE_4 = 0x4,
    PALETTE_5 = 0x5,
    PALETTE_6 = 0x6,
    PALETTE_7 = 0x7,
    PALETTE_8 = 0x8,
    PALETTE_9 = 0x9,
    PALETTE_A = 0xA,
    PALETTE_B = 0xB,
    PALETTE_C = 0xC,
    PALETTE_D = 0xD,
    PALETTE_E = 0xE,
    PALETTE_F = 0xF,
    PALETTE_LAST = PALETTE_F,
    PALETTE_MASK = -1
}

export class Palette {
    /** Array of palette colors, stored as RGBA */
    colors: Uint32Array;

    /**
     * Builds a new Palette object and sets the default colors
     */
    constructor() {
        this.colors = new Uint32Array([
            0xFFFFFFFF, // #FFFFFFFF
            0xFF000000, // #000000FF
            0xFF555555, // #555555FF
            0xFFAAAAAA, // #AAAAAAFF
            0xFF0000FF, // #FF0000FF
            0xFF0080FF, // #FF8000FF
            0xFF00FFFF, // #FFFF00FF
            0xFF00FF80, // #80FF00FF
            0xFF00FF00, // #00FF00FF
            0xFF80FF00, // #00FF80FF
            0xFFFFFF00, // #00FFFFFF
            0xFFFF8000, // #0080FFFF
            0xFFFF0000, // #0000FFFF
            0xFFFF0080, // #8000FFFF
            0xFFFF00FF, // #FF00FFFF
            0xFF8000FF // #FF0080FF
        ]);
    }
}